SELECT q.id, q.clinic_id AS clinicId, c.clinic_name AS clinicName, q.appointment_id AS appointmentId, a.appointment_no AS appointmentNo, a.appointment_date AS appointmentDate, q.patient_id AS patientId, p.patient_name AS patientName, p.mobile AS patientMobile, q.doctor_id AS doctorId, s.staff_name AS doctorName, q.queue_no AS queueNo, q.queue_status AS queueStatus, q.checkin_at AS checkinAt, q.call_at AS callAt, q.start_treatment_at AS startTreatmentAt, q.end_treatment_at AS endTreatmentAt, q.remark FROM queue_record q LEFT JOIN clinic c ON c.id = q.clinic_id LEFT JOIN appointment a ON a.id = q.appointment_id LEFT JOIN patient p ON p.id = q.patient_id LEFT JOIN staff s ON s.id = q.doctor_id WHERE q.org_id = #{orgId}
AND a.appointment_date = #{query.queueDate}
AND q.clinic_id = #{query.clinicId}
AND q.doctor_id = #{query.doctorId}
AND q.queue_status = #{query.queueStatus}
ORDER BY q.checkin_at DESC, q.id DESC
